import React, { useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiSearch, FiBook, FiAward, FiArrowRight, FiStar } from 'react-icons/fi';
import { useUser } from '../context/UserContext';

// Structured dynamic course data with varied platforms and links
const MOCK_SKILLS = [
    { 
        id: 1, 
        name: "Machine Learning & AI", 
        platforms: [
            { name: "Coursera", url: "https://www.coursera.org/learn/machine-learning" }, 
            { name: "edX", url: "https://www.edx.org/learn/machine-learning" },
            { name: "Udacity", url: "https://www.udacity.com/course/intro-to-machine-learning--ud120" }
        ], 
        category: "Trending", 
        description: "Master the core algorithms that power modern AI, including neural networks, deep learning, and predictive modeling." 
    },
    { 
        id: 2, 
        name: "React.js & Next.js", 
        platforms: [
            { name: "Udemy", url: "https://www.udemy.com/course/react-the-complete-guide-incl-redux/" }, 
            { name: "Pluralsight", url: "https://www.pluralsight.com/paths/react" }
        ], 
        category: "Web Dev", 
        description: "Build highly scalable, reactive, and SEO-friendly web applications using the latest JavaScript frameworks." 
    },
    { 
        id: 3, 
        name: "Cloud Architecture (AWS)", 
        platforms: [
            { name: "A Cloud Guru", url: "https://acloudguru.com/" }, 
            { name: "Coursera", url: "https://www.coursera.org/professional-certificates/aws-cloud-solutions-architect" }
        ], 
        category: "Cloud", 
        description: "Design robust, secure, and highly available cloud solutions optimized for enterprise scale." 
    },
    { 
        id: 4, 
        name: "UI/UX Design", 
        platforms: [
            { name: "Google", url: "https://grow.google/certificates/ux-design/" }, 
            { name: "IDF", url: "https://www.interaction-design.org/" }
        ], 
        category: "Design", 
        description: "Learn user research, wireframing, and prototyping to create intuitive and beautiful digital interfaces." 
    },
    { 
        id: 5, 
        name: "Cybersecurity Fundamentals", 
        platforms: [
            { name: "CompTIA", url: "https://www.comptia.org/certifications/security" }, 
            { name: "edX", url: "https://www.edx.org/learn/cybersecurity" }
        ], 
        category: "Security", 
        description: "Understand network security, risk management, and cryptography to protect critical infrastructure from modern threats." 
    },
    { 
        id: 6, 
        name: "Data Engineering", 
        platforms: [
            { name: "DataCamp", url: "https://www.datacamp.com/tracks/data-engineer-with-python" }, 
            { name: "Coursera", url: "https://www.coursera.org/specializations/data-engineering-gcp" }
        ], 
        category: "Data", 
        description: "Build and maintain data pipelines, data warehouses, and highly available data lakes for big data analytics." 
    },
    { 
        id: 7, 
        name: "Prompt Engineering", 
        platforms: [
            { name: "OpenAI", url: "https://platform.openai.com/docs/guides/prompt-engineering" }, 
            { name: "Udemy", url: "https://www.udemy.com/topic/prompt-engineering/" }
        ], 
        category: "Trending", 
        description: "Master the art of crafting precise prompts to extract maximal value and complex reasoning from Large Language Models." 
    },
    { 
        id: 8, 
        name: "Blockchain Development", 
        platforms: [
            { name: "Ethereum.org", url: "https://ethereum.org/en/developers/" }, 
            { name: "Coursera", url: "https://www.coursera.org/specializations/blockchain" }
        ], 
        category: "Web3", 
        description: "Develop decentralized applications (dApps), secure smart contracts, and understand cryptographic protocols." 
    },
];

const SkillsPage: React.FC = () => {
    const navigate = useNavigate();
    const { userProfile, addToLearningPath } = useUser();
    const [searchQuery, setSearchQuery] = useState('');
    const [toastMessage, setToastMessage] = useState('');

    const addPathItem = (skill: any) => {
        const id = skill.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
        if (userProfile.learningPath.some((entry) => entry.id === id)) {
            setToastMessage(`${skill.name} is already in your Learning Path.`);
            window.setTimeout(() => setToastMessage(''), 2500);
            return;
        }

        addToLearningPath({
            id,
            title: skill.name,
            platforms: skill.platforms,
            status: 'Not Started',
            dateAdded: new Date().toLocaleDateString()
        });
        setToastMessage(`${skill.name} added to your Learning Path.`);
        window.setTimeout(() => setToastMessage(''), 2500);
    };

    const filteredSkills = useMemo(() => {
        if (!searchQuery.trim()) {
            return MOCK_SKILLS;
        }
        const lowerQuery = searchQuery.toLowerCase();
        return MOCK_SKILLS.filter(skill => 
            skill.name.toLowerCase().includes(lowerQuery) || 
            skill.category.toLowerCase().includes(lowerQuery) ||
            skill.description.toLowerCase().includes(lowerQuery)
        );
    }, [searchQuery]);

    return (
        <div className="min-h-screen bg-white text-slate-900 pb-12 font-sans relative overflow-hidden">
            {/* Background Elements */}
            <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-100 rounded-full blur-[120px]"></div>
            <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-100 rounded-full blur-[120px]"></div>

            {/* Header section */}
            <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-20">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
                    <div className="flex items-center gap-3">
                        <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-2.5 rounded-xl shadow-lg shadow-blue-500/30">
                            <FiBook className="text-white" size={24} />
                        </div>
                        <h1 className="text-xl md:text-2xl font-extrabold text-slate-900 tracking-tight">
                            Your Personalised Skill Recommendation
                        </h1>
                    </div>
                </div>
            </header>

            <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8 space-y-10 relative z-10">
                {/* Hero / Search Section */}
                <div className="relative rounded-3xl overflow-hidden shadow-2xl bg-white border border-slate-200 shadow-slate-200/50">
                    {/* Decorative elements */}
                    <div className="absolute top-0 right-0 -mt-20 -mr-20 w-80 h-80 bg-blue-500/10 rounded-full blur-3xl"></div>
                    <div className="absolute bottom-0 left-0 -mb-20 -ml-20 w-72 h-72 bg-purple-500/10 rounded-full blur-3xl"></div>

                    <div className="relative p-10 md:p-16 text-center z-10">
                        <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 mb-6 tracking-tight">
                            What will you <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-indigo-600">master next?</span>
                        </h2>
                        <p className="text-lg text-slate-600 mb-10 max-w-2xl mx-auto font-medium">
                            Discover trending skills and find the best platforms to accelerate your career growth based on your profile.
                        </p>
                        {toastMessage && (
                            <div className="mx-auto mb-6 inline-flex items-center justify-center rounded-3xl border border-blue-100 bg-blue-50 px-5 py-3 text-sm font-semibold text-blue-700 shadow-sm">
                                {toastMessage}
                            </div>
                        )}
                        <div className="max-w-3xl mx-auto relative group">
                            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                                <FiSearch className="h-6 w-6 text-slate-400 group-focus-within:text-blue-600 transition-colors" />
                            </div>
                            <input
                                type="text"
                                className="block w-full pl-12 pr-4 py-5 rounded-2xl text-lg text-slate-900 placeholder-slate-400 bg-white border border-slate-300 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all duration-300 shadow-sm"
                                placeholder="Search for skills, roles, or topics..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>
                    </div>
                </div>

                {/* Content Section */}
                <div>
                    <div className="flex items-center justify-between mb-8">
                        <h3 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                            {searchQuery ? (
                                <>Search Results <span className="text-slate-500 text-lg font-normal">({filteredSkills.length})</span></>
                            ) : (
                                <><FiStar className="text-yellow-500 fill-current" /> Trending Now</>
                            )}
                        </h3>
                    </div>

                    {filteredSkills.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {filteredSkills.map((skill) => (
                                <div 
                                    key={skill.id} 
                                    className="bg-white rounded-2xl p-6 border border-slate-200 hover:border-blue-300 hover:shadow-xl shadow-sm transition-all duration-300 flex flex-col h-full group"
                                >
                                    <div className="flex justify-between items-start mb-4">
                                        <div className="bg-blue-50 text-blue-700 border border-blue-100 text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">
                                            {skill.category}
                                        </div>
                                        <div className="w-10 h-10 rounded-full bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-400 group-hover:bg-blue-600 group-hover:text-white group-hover:border-blue-500 transition-colors duration-300">
                                            <FiAward size={20} />
                                        </div>
                                    </div>

                                    <h4 className="text-xl font-bold text-slate-900 mb-2 leading-tight">
                                        {skill.name}
                                    </h4>

                                    <p className="text-slate-600 text-sm mb-6 flex-grow font-medium">
                                        {skill.description}
                                    </p>

                                    <div className="space-y-4 mt-auto">
                                        <div className="flex flex-wrap gap-2">
                                            {skill.platforms.map((platform, idx) => (
                                                <a 
                                                    key={idx} 
                                                    href={platform.url}
                                                    target="_blank"
                                                    rel="noopener noreferrer"
                                                    className="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-bold bg-slate-100 text-slate-700 border border-slate-200 hover:bg-blue-50 hover:text-blue-700 hover:border-blue-200 transition-colors"
                                                >
                                                    {platform.name}
                                                </a>
                                            ))}
                                        </div>

                                        <div className="space-y-3">
                                            <button
                                                onClick={() => navigate(`/skill/${skill.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')}`)}
                                                className="w-full flex items-center justify-center gap-2 bg-slate-50 hover:bg-blue-600 text-slate-700 hover:text-white border border-slate-200 hover:border-blue-600 py-3 rounded-xl font-bold transition-all duration-300 group/btn"
                                            >
                                                <span>View Skill</span>
                                                <FiArrowRight className="transform group-hover/btn:translate-x-1 transition-transform" />
                                            </button>
                                            <button
                                                onClick={() => addPathItem(skill)}
                                                className={`w-full rounded-xl py-3 font-bold transition-all ${userProfile.learningPath.some((entry) => entry.id === skill.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')) ? 'bg-slate-200 text-slate-500 cursor-not-allowed' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
                                                disabled={userProfile.learningPath.some((entry) => entry.id === skill.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''))}
                                            >
                                                {userProfile.learningPath.some((entry) => entry.id === skill.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')) ? 'Added' : 'Add to Learning Path'}
                                            </button>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="text-center py-20 bg-white rounded-3xl border border-slate-200 shadow-sm">
                            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-50 border border-slate-100 mb-4">
                                <FiSearch className="h-8 w-8 text-slate-400" />
                            </div>
                            <h3 className="text-xl font-bold text-slate-900 mb-2">No skills found</h3>
                            <p className="text-slate-500 max-w-md mx-auto font-medium">
                                We couldn't find any skills matching "{searchQuery}". Try searching for something else or explore our trending skills.
                            </p>
                            <button 
                                onClick={() => setSearchQuery('')}
                                className="mt-6 text-blue-600 font-bold hover:text-blue-700 transition-colors"
                            >
                                Clear search
                            </button>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
};

export default SkillsPage;
